<script setup lang="ts">
/**
 * Home — scoped to the active book.
 *
 * Replaces the old "all 6 books" grid: now shows the chapters of whichever
 * book the student picked at onboarding. To switch books, go to Settings →
 * "تغییر کتاب".
 */
import { onMounted, ref, computed } from 'vue';
import type { ArticleSummary, Chapter } from '@shared/types';
import { pmApi } from '@/api/client';
import { useActiveBookStore } from '@/stores/activeBook';

const activeBook = useActiveBookStore();

const chapters = ref<Chapter[]>([]);
const recent = ref<ArticleSummary[]>([]);
const loading = ref(true);
const error = ref<string | null>(null);

const bookMeta = computed(() => activeBook.meta);
const bookGradient = computed(() => {
  const m = bookMeta.value;
  return m ? `linear-gradient(160deg, ${m.color1} 0%, ${m.color2} 100%)` : '';
});

onMounted(async () => {
  if (!activeBook.slug) {
    // Defence in depth — router should have already redirected.
    loading.value = false;
    return;
  }
  try {
    chapters.value = await pmApi.getChapters(activeBook.slug);
  } catch (e) {
    error.value = (e as Error).message;
  } finally {
    loading.value = false;
  }

  try {
    recent.value = await pmApi.getRecent(8);
  } catch {
    recent.value = [];
  }
});
</script>

<template>
  <main class="pm-home-bg px-4 pt-6 pb-16">
    <!-- Brand strip -->
    <div class="flex items-center gap-3 mb-5">
      <img src="/logo.jpg" alt="منِ فیزیکی" class="pm-brand-logo-sm shrink-0" />
      <div class="flex-1 min-w-0">
        <div class="font-fancy text-xl text-ink leading-tight">منِ فیزیکی</div>
        <div class="text-[11px] text-gray-500">آموزش فیزیک به زبان ساده</div>
      </div>
    </div>

    <!-- Active-book banner -->
    <header
      v-if="bookMeta"
      class="rounded-2xl p-5 mb-6 text-white shadow-md flex items-center gap-4"
      :style="{ background: bookGradient }"
    >
      <div class="text-5xl shrink-0">{{ bookMeta.emoji }}</div>
      <div class="flex-1 min-w-0">
        <div class="text-xs opacity-80">کتاب فعال</div>
        <div class="font-bold text-lg leading-tight">{{ bookMeta.label }}</div>
        <div class="text-xs opacity-80 mt-1">
          {{ bookMeta.chapterCount }} فصل · {{ bookMeta.lessonCount }} درس
        </div>
      </div>
      <RouterLink
        to="/settings"
        class="text-xs bg-white/20 rounded-lg px-3 py-2 hover:bg-white/30 transition-colors shrink-0"
      >
        تغییر کتاب
      </RouterLink>
    </header>

    <!-- Recent strip — silent if empty / failed -->
    <section v-if="recent.length" class="mb-8">
      <h2 class="font-fancy text-2xl mb-3">تازه‌ها</h2>
      <div class="-mx-4 overflow-x-auto scrollbar-thin">
        <ul class="flex gap-3 px-4 snap-x snap-mandatory">
          <li
            v-for="a in recent"
            :key="a.slug"
            class="snap-start shrink-0 w-48"
          >
            <RouterLink
              :to="`/article/${a.slug}`"
              class="block h-full bg-white rounded-xl shadow-sm border border-gray-200 p-3 hover:border-olive transition-colors"
            >
              <img
                v-if="a.thumbUrl"
                :src="a.thumbUrl"
                :alt="a.title"
                loading="lazy"
                class="w-full h-24 object-cover rounded-md mb-2 bg-cream"
              />
              <div class="font-bold text-sm leading-snug line-clamp-2">{{ a.title }}</div>
              <div v-if="a.readingTime" class="text-[10px] text-gray-500 mt-2">⏱ {{ a.readingTime }}</div>
            </RouterLink>
          </li>
        </ul>
      </div>
    </section>

    <!-- Chapters of the active book -->
    <h2 class="font-fancy text-2xl mb-3">فصل‌ها</h2>

    <div v-if="loading" class="text-center py-12 text-gray-500">در حال بارگذاری…</div>
    <div v-else-if="error" class="text-center py-12 text-red-600">{{ error }}</div>
    <div v-else-if="!chapters.length" class="text-center py-12 text-gray-500">فصلی یافت نشد.</div>
    <ul v-else class="space-y-2">
      <li v-for="ch in chapters" :key="ch.slug">
        <RouterLink
          :to="`/chapter/${ch.slug}`"
          class="flex items-center justify-between bg-white rounded-xl shadow-sm border border-gray-200
                 px-4 py-3 hover:border-olive transition-colors"
        >
          <div class="min-w-0 flex-1">
            <div class="font-bold text-sm leading-snug line-clamp-2">{{ ch.title }}</div>
            <div class="text-xs text-gray-500 mt-1">{{ ch.lessonCount }} درس</div>
          </div>
          <span class="text-olive text-xl ms-3">←</span>
        </RouterLink>
      </li>
    </ul>
  </main>
</template>
